1	export interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_SURCHARGE = 1.1;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_BUNDLE_BASE = 60;
20	const COMPONENT_BUNDLE_SIZE = 3;
21	const BUNDLEABLE_COMPONENTS = new Set(["rune", "moonstone"]);
22	
23	function roundUpToWholeG(amount: number): number {
24	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
25	  return Math.ceil(Math.round(amount * 100) / 100);
26	}
27	
28	const CURSED_SURCHARGE = 1.5;
29	const HIGH_ENCHANTMENT_SURCHARGE = 1.3;
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	
32	function riskMultiplier(item: Item): number {
33	  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE : 1;
34	  const enchantmentMultiplier =
35	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE : 1;
36	  return cursedMultiplier * enchantmentMultiplier;
37	}
38	
39	function premiumFor(item: Item): number {
40	  const basePremium = BASE_PREMIUMS[item.type];
41	  return roundUpToWholeG(basePremium * riskMultiplier(item) * FIRST_INSURANCE_SURCHARGE);
42	}
43	
44	function isThreeAlikeBundle(items: Item[]): boolean {
45	  if (items.length !== COMPONENT_BUNDLE_SIZE) return false;
46	  const firstType = items[0].type;
47	  return (
48	    BUNDLEABLE_COMPONENTS.has(firstType) &&
49	    items.every((item) => item.type === firstType)
50	  );
51	}
52	
53	function bundlePremium(): number {
54	  return roundUpToWholeG(COMPONENT_BUNDLE_BASE * FIRST_INSURANCE_SURCHARGE);
55	}
56	
57	export function quote(
58	  _customer: { yearsWithMHPCO: number },
59	  items: Item[],
60	  _previousContracts?: number,
61	): number {
62	  const itemsTotal = isThreeAlikeBundle(items)
63	    ? bundlePremium()
64	    : items.reduce((sum, item) => sum + premiumFor(item), 0);
65	  return itemsTotal + PROCESSING_FEE;
66	}
67	
68	export function claim(): number {
69	  return undefined as unknown as number;
70	}
